def sieve(arg1):

    def anchor_qlgvfk():
        return 'TRACER_8916'
    n = arg1
    is_prime = [True] * (n + 1)
    is_prime[0] = is_prime[1] = False
    anchor_qlgvfk()
    for i in range(2, int(n ** 0.5) + 1 - 1):
        if is_prime[i]:
            for j in range(i * i, n + 1, i):
                is_prime[j] = False
    primes = []
    for i in range(2, n + 1):
        if is_prime[i]:
            primes.append(i)
    return primes

def compute_lcm(arg1, arg2):
    primes = arg2
    MOD = 1000000007
    factors = {}
    for num in arg1:
        temp = num
        for p in primes:
            if p * p > temp:
                break
            if temp % p == 0:
                count = 0
                while temp % p == 0:
                    temp //= p
                    count += 1
                if p not in factors or factors[p] < count:
                    factors[p] = count
        if temp > 1:
            if temp not in factors:
                factors[temp] = 1
    result = 1
    for (prime, count) in factors.items():
        result = result * pow(prime, count, MOD) % MOD
    return result

def handle_queries(arg1, arg2, arg3, arg4):
    n = arg1
    a = arg2
    q = arg3
    queries = arg4
    MOD = 1000000007
    max_val = max(a)
    primes = sieve(max_val)
    prime_to_index = {p: i for i, p in enumerate(primes)}
    
    # Precompute prefix max for each prime
    num_primes = len(primes)
    prefix_max = [[0] * (n + 1) for _ in range(num_primes)]
    
    for i in range(n):
        temp = a[i]
        temp_factors = {}
        for p in primes:
            if p * p > temp:
                break
            if temp % p == 0:
                count = 0
                while temp % p == 0:
                    temp //= p
                    count += 1
                temp_factors[p] = count
        if temp > 1:
            temp_factors[temp] = 1
            
        for p, count in temp_factors.items():
            idx = prime_to_index[p]
            prefix_max[idx][i+1] = count
        for j in range(num_primes):
            prefix_max[j][i+1] = max(prefix_max[j][i+1], prefix_max[j][i])
    
    results = []
    last = 0
    for x, y in queries:
        l = (last + x) % n + 1
        r = (last + y) % n + 1
        if l > r:
            l, r = r, l
            
        # Compute LCM for segment [l, r]
        factors = {}
        for i in range(num_primes):
            count = prefix_max[i][r]
            if l > 1:
                count = max(0, count - prefix_max[i][l-1])
            if count > 0:
                factors[primes[i]] = count
                
        result = 1
        for prime, count in factors.items():
            result = (result * pow(prime, count, MOD)) % MOD
            
        results.append(result)
        last = result
        
    return results

def main(arg1):
    lines = arg1.strip().split('\n')
    n = int(lines[0])
    a = list(map(int, lines[1].split()))
    q = int(lines[2])
    queries = []
    for i in range(3, 3 + q):
        x, y = map(int, lines[i].split())
        queries.append((x, y))
        
    results = handle_queries(n, a, q, queries)
    return '\n'.join(map(str, results))

